param([Parameter(Mandatory=$true)][string]$IncomingRoot,[Parameter(Mandatory=$true)][string]$RunId)
$ErrorActionPreference='Stop';$target='macd';$runtime='NoraPhase2MacdRuntimeV3.mqh';$tester='NoraPhase2MacdTesterCanaryV3.mq5';$editor='C:\Program Files\Darwinex MetaTrader 5\MetaEditor64.exe';$root="$env:USERPROFILE\NoraPhase2U";$run=Join-Path $root $RunId
function Hash($p){(Get-FileHash $p -Algorithm SHA256).Hash.ToLowerInvariant()};function Rel($p){$p.Substring($run.Length+1).Replace('\','/')}
New-Item -ItemType Directory -Force $run|Out-Null;$source=Join-Path $run 'source';New-Item -ItemType Directory -Force $source|Out-Null
$record=[ordered]@{contract_version='nora.phase2.compiler_record_v1';target_identifier=$target;source_runtime_path=('source/'+$runtime);source_runtime_sha256=$null;tester_source_path=('source/'+$tester);tester_source_sha256=$null;metaeditor_executable_path=$editor;command=$null;arguments=@();started_utc=(Get-Date).ToUniversalTime().ToString('o');completion_state='incomplete';process_exit_status=$null;compiler_success=$false;warning_count=0;warnings=@();error_count=0;errors=@();compiler_log_relative_path='compile.log';compiler_log_sha256=$null;expected_ex5_relative_path=('source/'+$tester.Replace('.mq5','.ex5'));ex5_exists=$false;ex5_size=$null;ex5_sha256=$null;failure_reason=$null}
try {foreach($name in @($runtime,$tester)){if(!(Test-Path (Join-Path $IncomingRoot $name))){throw "missing source: $name"};Copy-Item (Join-Path $IncomingRoot $name) (Join-Path $source $name) -Force};$program=Join-Path $source $tester;$log=Join-Path $run 'compile.log';$ex5=Join-Path $source $tester.Replace('.mq5','.ex5');$record.source_runtime_sha256=Hash (Join-Path $source $runtime);$record.tester_source_sha256=Hash $program;if(!(Test-Path $editor)){throw 'missing compiler'};$args=@('/compile:"'+$program+'"','/log:"'+$log+'"');$record.arguments=$args;$record.command=$editor+' '+($args -join ' ');$start=Get-Date;$p=Start-Process -FilePath $editor -ArgumentList $args -PassThru;$p.WaitForExit();$record.process_exit_status=$p.ExitCode;if($p.ExitCode -ne 0){throw 'nonzero compiler exit'};if(!(Test-Path $log)){throw 'missing compiler log'};$record.compiler_log_sha256=Hash $log;$lines=Get-Content $log;$record.warnings=@($lines|Where-Object {$_ -match '(?i)warning'});$record.errors=@($lines|Where-Object {$_ -match '(?i)error'});$record.warning_count=$record.warnings.Count;$record.error_count=$record.errors.Count;if($record.error_count){throw 'compiler errors'};if(!(Test-Path $ex5)){throw 'missing EX5'};$item=Get-Item $ex5;if($item.LastWriteTimeUtc -lt $start.ToUniversalTime()){throw 'stale EX5'};$record.ex5_exists=$true;$record.ex5_size=$item.Length;$record.ex5_sha256=Hash $ex5;$record.completion_state='completed';$record.compiler_success=$true} catch {$record.failure_reason=$_.Exception.Message;$record.completion_state='failed'} finally {$record.completed_utc=(Get-Date).ToUniversalTime().ToString('o');$record|ConvertTo-Json -Depth 8|Set-Content (Join-Path $run 'compile.json') -Encoding utf8}
if(!$record.compiler_success){exit 2}
